mapper.select:
select id, from_user_id as fromUserId, to_user_id as toUserId, content, status, create_time as createTime, delivered_time as deliveredTime, acked_time as ackedTime, read_time as readTime from tb_private_message where (from_user_id = #{myId} and to_user_id = #{withUserId}) or (from_user_id = #{withUserId} and to_user_id = #{myId})
and id < #{beforeId}
order by id desc limit #{pageSize}

mapper.update:
update tb_private_message
set status = #{readStatus},
    delivered_time = ifnull(delivered_time, #{readTime}),
    acked_time = ifnull(acked_time, #{readTime}),
    read_time = #{readTime},
    update_time = #{readTime}
where from_user_id = #{withUserId}
  and to_user_id = #{myId}

  and id <= #{upToMsgId}

  and (status <> #{readStatus})

update tb_private_message
set status = #{readStatus},
    delivered_time = ifnull(delivered_time, #{readTime}),
    acked_time = ifnull(acked_time, #{readTime}),
    read_time = #{readTime},
    update_time = #{readTime}
where to_user_id = #{myId}
  and id in

    #{id}

update tb_private_message
set status = case
                 when status = #{savedStatus} then #{deliveredStatus}
                 else status
             end,
    delivered_time = ifnull(delivered_time, #{deliveredTime}),
    update_time = #{deliveredTime}
where to_user_id = #{myId}
  and id in

    #{id}

  and status <> 3

update tb_private_message
set status = case
                 when status in (#{savedStatus}, #{deliveredStatus}) then #{ackedStatus}
                 else status
             end,
    delivered_time = ifnull(delivered_time, #{ackedTime}),
    acked_time = ifnull(acked_time, #{ackedTime}),
    update_time = #{ackedTime}
where id = #{serverMsgId}
  and to_user_id = #{myId}
  and status <> #{failStatus}
